// Transform Google Ads API response to common schema.
// IMPORTANT: Google Ads API returns LIFETIME CUMULATIVE metrics — each value
// is the running total since campaign launch. Performance ID is keyed by
// (campaign_id, date) only (no hour) so subsequent same-day runs UPSERT and
// overwrite with the latest cumulative figure. Aggregation logic in readers
// must take the LATEST snapshot per campaign to get totals.
const items = $input.all();

// Handle upstream error / empty data (continueOnFail produces error item)
if (!items.length || items[0].json?.error || items[0].json?.message?.includes?.('403')) {
  return [{json: {skip: true, reason: 'Google Ads API unavailable'}}];
}

const results = [];
const now = new Date().toISOString().split('T')[0];
const hour = new Date().toISOString().split('T')[1].substring(0, 5);

for (const item of items) {
  const d = item.json;
  const metrics = d.metrics || d;
  const campaign = d.campaign || {};

  const impressions = parseInt(metrics.impressions || 0);
  // Google Ads API returns 'interactions' (superset of clicks); fall back to clicks if present
  const clicks = parseInt(metrics.clicks || metrics.interactions || 0);
  const costMicros = parseInt(metrics.costMicros || metrics.cost_micros || 0);
  const conversions = parseFloat(metrics.conversions || 0);
  const videoViews = parseInt(metrics.videoViews || metrics.video_views || 0);

  const spendZAR = costMicros / 1000000;
  const ctr = impressions > 0 ? clicks / impressions : 0;
  const cpc = clicks > 0 ? spendZAR / clicks : 0;
  const cpm = impressions > 0 ? (spendZAR / impressions) * 1000 : 0;
  const cpa = conversions > 0 ? spendZAR / conversions : 0;
  const roas = spendZAR > 0 ? (conversions * 100) / spendZAR : 0;

  // n8n Google Ads node returns flat structure: d.name, d.id (not nested under campaign)
  const campaignName = campaign.name || d.name || d.campaignName || 'Unknown';
  const campaignId = campaign.id || d.id || 'unknown';

  results.push({
    json: {
      // Performance ID = (platform, campaign, date) — no hour, enables upsert
      'Performance ID': `gads_${campaignId}_${now}`,
      'Campaign Name': campaignName,
      'Platform': 'google_ads',
      'Date': now,
      'Impressions': impressions,
      'Clicks': clicks,
      'CTR': parseFloat(ctr.toFixed(4)),
      'Spend ZAR': parseFloat(spendZAR.toFixed(2)),  // lifetime cumulative
      'Conversions': Math.round(conversions),
      'CPA ZAR': parseFloat(cpa.toFixed(2)),
      'ROAS': parseFloat(roas.toFixed(2)),
      'CPM ZAR': parseFloat(cpm.toFixed(2)),
      'CPC ZAR': parseFloat(cpc.toFixed(2)),
      'Video Views': videoViews,
      'Engagement Rate': 0,
      'Snapshot Hour': hour,  // kept for debugging; not part of upsert key
    }
  });
}

return results.length > 0 ? results : [{json: {skip: true, reason: 'No Google Ads data'}}];

// Transform Meta Ads insights to common schema, LEFT-JOINED with the canonical
// campaign list so every ACTIVE/PAUSED campaign gets an Ad_Performance row
// even when it has zero delivery today. Reads two upstream nodes:
//   - 'Meta List Campaigns' : canonical list with id, name, status, effective_status
//   - 'Meta Ads Get Insights' : today's insights (campaigns with zero delivery are absent)
const now = new Date().toISOString().split('T')[0];
const hour = new Date().toISOString().split('T')[1].substring(0, 5);

// 1. Pull campaign list — this is the canonical set we emit rows for
let campaignList = [];
try {
  const listResp = $('Meta List Campaigns').first()?.json || {};
  campaignList = listResp.data || [];
} catch (e) {
  // Meta List Campaigns node didn't run (e.g. credential missing). Fall back
  // to whatever insights we have so behaviour degrades to the old code path.
  campaignList = [];
}

// 2. Pull insights and index by campaign_id
let insightsById = {};
try {
  const insResp = $('Meta Ads Get Insights').first()?.json || {};
  const arr = insResp.data || (insResp.impressions !== undefined ? [insResp] : []);
  for (const d of arr) {
    if (d.campaign_id) insightsById[d.campaign_id] = d;
  }
} catch (e) {
  insightsById = {};
}

// If we have neither list nor insights, the Meta side is effectively unavailable
if (campaignList.length === 0 && Object.keys(insightsById).length === 0) {
  return [{json: {skip: true, reason: 'Meta Ads API unavailable'}}];
}

// 3. Build emission set: start from campaignList when present, otherwise from insights
const baseSet = campaignList.length > 0
  ? campaignList.map(c => ({
      id: c.id,
      name: c.name,
      status: c.status,
      effective_status: c.effective_status,
    }))
  : Object.values(insightsById).map(d => ({
      id: d.campaign_id,
      name: d.campaign_name,
      status: '',
      effective_status: '',
    }));

const results = [];
for (const c of baseSet) {
  const d = insightsById[c.id] || {};
  const impressions = parseInt(d.impressions || 0);
  const clicks = parseInt(d.clicks || 0);
  const spend = parseFloat(d.spend || 0);
  const reach = parseInt(d.reach || 0);

  let conversions = 0;
  if (d.actions) {
    for (const action of d.actions) {
      if (action.action_type === 'lead' || action.action_type === 'complete_registration' || action.action_type === 'purchase') {
        conversions += parseInt(action.value || 0);
      }
    }
  }

  const ctr = impressions > 0 ? clicks / impressions : 0;
  const cpc = clicks > 0 ? spend / clicks : 0;
  const cpm = impressions > 0 ? (spend / impressions) * 1000 : 0;
  const cpa = conversions > 0 ? spend / conversions : 0;
  const roas = spend > 0 ? (conversions * 100) / spend : 0;
  const engRate = reach > 0 ? clicks / reach : 0;

  results.push({
    json: {
      // Performance ID = (platform, campaign, date) — enables upsert.
      'Performance ID': `meta_${c.id || 'unknown'}_${now}`,
      'Campaign Name': c.name || d.campaign_name || 'Unknown',
      'Platform': 'meta_ads',
      'Date': now,
      'Impressions': impressions,
      'Clicks': clicks,
      'CTR': parseFloat(ctr.toFixed(4)),
      'Spend ZAR': parseFloat(spend.toFixed(2)),
      'Conversions': conversions,
      'CPA ZAR': parseFloat(cpa.toFixed(2)),
      'ROAS': parseFloat(roas.toFixed(2)),
      'CPM ZAR': parseFloat(cpm.toFixed(2)),
      'CPC ZAR': parseFloat(cpc.toFixed(2)),
      'Video Views': parseInt(d.video_views || 0),
      'Engagement Rate': parseFloat(engRate.toFixed(4)),
      'Snapshot Hour': hour,
    }
  });
}

return results.length > 0 ? results : [{json: {skip: true, reason: 'No Meta Ads data'}}];

// Filter out skip items (no data from platform)
const items = $input.all();
return items.filter(item => !item.json.skip);

// Detect anomalies: spend > 2x daily budget, CTR drop > 50% vs 7-day avg
const items = $input.all();
const anomalies = [];
const DAILY_CAP = 666;

for (const item of items) {
  const d = item.json;
  if (d.skip) continue;

  const issues = [];

  // Check spend against daily cap
  if (d['Spend ZAR'] > DAILY_CAP) {
    issues.push(`Spend R${d['Spend ZAR']} exceeds daily cap R${DAILY_CAP}`);
  }

  // Flag very low CTR (potential issue)
  if (d.Impressions > 1000 && d.CTR < 0.001) {
    issues.push(`CTR ${(d.CTR * 100).toFixed(2)}% critically low with ${d.Impressions} impressions`);
  }

  // Flag high CPA
  if (d['CPA ZAR'] > 800 && d.Conversions > 0) {
    issues.push(`CPA R${d['CPA ZAR']} exceeds R800 threshold`);
  }

  if (issues.length > 0) {
    anomalies.push({
      json: {
        campaign: d['Campaign Name'],
        platform: d.Platform,
        date: d.Date,
        issues: issues,
        spendZAR: d['Spend ZAR'],
        ctr: d.CTR,
        cpa: d['CPA ZAR'],
        severity: d['Spend ZAR'] > DAILY_CAP ? 'CRITICAL' : 'WARNING',
      }
    });
  }
}

if (anomalies.length > 0) {
  return anomalies;
} else {
  return [{json: {noAnomalies: true}}];
}
